export const getUpdateSettingsUrl = (companyId: string,) => {




  return `/api/settings/${companyId}`
}

/**
 * @summary Update company settings
 */
export const updateSettings = async (companyId: string,
    settingsUpdate: SettingsUpdate, options?: RequestInit): Promise<Settings> => {

  return customFetch<Settings>(getUpdateSettingsUrl(companyId),
  {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      settingsUpdate,)
  }
);}




export const getUpdateSettingsMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateSettings>>, TError,{companyId: string;data: BodyType<SettingsUpdate>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof updateSettings>>, TError,{companyId: string;data: BodyType<SettingsUpdate>}, TContext> => {

const mutationKey = ['updateSettings'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof updateSettings>>, {companyId: string;data: BodyType<SettingsUpdate>}> = (props) => {
          const {companyId,data} = props ?? {};

          return  updateSettings(companyId,data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

